import requests

def test_allergy_intolerance_invalid_patient_reference_returns_400():
    base_url = 'http://localhost:8080'
    headers = {'Authorization': 'Bearer <clinician_token>', 'Content-Type': 'application/fhir+json'}

    payload = {
        'resourceType': 'AllergyIntolerance',
        'patient': {'reference': 'Patient/pt-nonexistent'},
        'code': {'coding': [{'system': 'http://snomed.info/sct', 'code': '373270004'}]},
        'status': 'active'
    }

    resp = requests.post(f'{base_url}/AllergyIntolerance', json=payload, headers=headers)
    assert resp.status_code in [400, 422], f'Expected 400 or 422, got {resp.status_code}'
    assert resp.json()['resourceType'] == 'OperationOutcome'

import requests

def test_allergy_intolerance_severity_boundary_codes():
    base_url = 'http://localhost:8080'
    headers = {'Authorization': 'Bearer <clinician_token>', 'Content-Type': 'application/fhir+json'}

    for severity in ['mild', 'severe']:
        payload = {
            'resourceType': 'AllergyIntolerance',
            'patient': {'reference': 'Patient/pt-004'},
            'code': {'coding': [{'system': 'http://snomed.info/sct', 'code': '373270004'}]},
            'status': 'active',
            'severity': severity
        }
        resp = requests.post(f'{base_url}/AllergyIntolerance', json=payload, headers=headers)
        assert resp.status_code == 201, f'Failed for severity={severity}: {resp.text}'
        assert resp.json()['severity'] == severity
